if(!window.MM) window.MM={};
window.MM['oph_p2_conjunctiva']=[
  {q:"A patient presents with bilateral red eyes, itching, ropy discharge, and recurrent seasonal symptoms. Which diagnosis is most likely?",o:["Viral conjunctivitis","Bacterial conjunctivitis","Trachoma","Allergic conjunctivitis","Episcleritis"],a:3,e:"Allergic conjunctivitis classically presents with intense itching, bilateral redness, and stringy or ropy mucoid discharge.<br><br>Itching is the hallmark symptom and helps distinguish allergic disease from infective conjunctivitis. Papillae are commonly seen on the tarsal conjunctiva.<br><br>Viral conjunctivitis (A) usually has watery discharge and preauricular lymphadenopathy, while bacterial conjunctivitis (B) produces mucopurulent discharge.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which organism is the most common cause of hyperacute purulent conjunctivitis?",o:["Staphylococcus aureus","Chlamydia trachomatis","Neisseria gonorrhoeae","Adenovirus","Haemophilus influenzae"],a:2,e:"Neisseria gonorrhoeae causes hyperacute conjunctivitis characterized by profuse purulent discharge, marked chemosis, and rapid corneal involvement. Public recall notes repeatedly emphasize gonococcus as the hyperacute cause.<br><br>The condition is an ophthalmic emergency because corneal perforation can occur rapidly. Immediate systemic antibiotics are required.<br><br>Adenovirus (D) usually causes watery follicular conjunctivitis rather than hyperacute purulent disease.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with viral conjunctivitis most commonly demonstrates which associated sign?",o:["Giant papillae","Preauricular lymphadenopathy","Hypopyon","Cherry-red spot","Corneal graft rejection"],a:1,e:"Viral conjunctivitis, especially adenoviral infection, commonly produces tender preauricular lymphadenopathy. This is repeatedly highlighted in recall MCQs.<br><br>Watery discharge, follicles, and recent upper respiratory tract infection are common associated findings. Vernal keratoconjunctivitis with giant papillae and shield ulcer is a classic recognition pattern.<br><br>Giant papillae (A) are more characteristic of vernal keratoconjunctivitis and contact lens-related disease.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is considered the hallmark of allergic conjunctivitis?",o:["Itching","Pain","Photophobia","Diplopia","Floaters"],a:0,e:"Itching is the cardinal symptom of allergic conjunctivitis and is considered the most important clinical clue in examination recalls.<br><br>Other findings include bilateral redness, tearing, and stringy mucoid discharge. Seasonal variation is also common.<br><br>Pain (B) and marked photophobia (C) should raise suspicion for corneal or intraocular pathology rather than simple allergy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of conjunctivitis is most commonly associated with follicles?",o:["Viral conjunctivitis","Bacterial conjunctivitis","Allergic conjunctivitis","Blepharitis","Dry eye disease"],a:0,e:"Follicles are small lymphoid elevations commonly seen in viral and chlamydial conjunctivitis. Adenoviral infection is the classic cause.<br><br>Patients often have watery discharge, conjunctival injection, and preauricular lymph node enlargement.<br><br>Bacterial conjunctivitis (B) typically produces papillary reaction and mucopurulent discharge rather than prominent follicles.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A child develops bilateral conjunctivitis with thick purulent discharge causing eyelids to stick together in the morning. Which diagnosis is most likely?",o:["Viral conjunctivitis","Allergic conjunctivitis","Episcleritis","Bacterial conjunctivitis","Keratitis"],a:3,e:"Bacterial conjunctivitis commonly presents with mucopurulent discharge and eyelid matting, especially on waking.<br><br>Common pathogens include Staphylococcus aureus, Streptococcus pneumoniae, and Haemophilus influenzae.<br><br>Viral conjunctivitis (A) usually causes watery discharge rather than thick purulent secretions.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival finding is classically associated with vernal keratoconjunctivitis?",o:["Giant papillae","Follicles","Pinguecula","Bitot spots","Pterygium"],a:0,e:"Vernal keratoconjunctivitis classically demonstrates giant cobblestone papillae on the upper tarsal conjunctiva. Public recall posts frequently describe \"cobblestone papillae\" as a hallmark sign.<br><br>The condition commonly affects young males with atopy and worsens during warm seasons.<br><br>Follicles (B) are more typical of viral and chlamydial conjunctivitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which organism is most commonly associated with trachoma?",o:["Chlamydia trachomatis","Adenovirus","Neisseria gonorrhoeae","Staphylococcus epidermidis","Moraxella"],a:0,e:"Trachoma is caused by Chlamydia trachomatis serotypes A, B, Ba, and C and remains an important cause of preventable blindness worldwide.<br><br>Repeated infection leads to conjunctival scarring, entropion, trichiasis, and corneal opacity.<br><br>Adenovirus (B) commonly causes epidemic keratoconjunctivitis rather than chronic cicatrizing disease.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with epidemic keratoconjunctivitis is most likely infected with:",o:["Adenovirus","Chlamydia","Gonococcus","Pneumococcus","Moraxella"],a:0,e:"Epidemic keratoconjunctivitis is caused by adenovirus and is highly contagious. Public recalls frequently identify adenovirus as the commonest viral conjunctivitis agent.<br><br>Patients develop watery discharge, follicles, preauricular lymphadenopathy, and punctate keratitis. Hyperacute gonococcal conjunctivitis with risk of corneal perforation is a high-stakes emergency.<br><br>Gonococcus (C) causes hyperacute purulent conjunctivitis rather than epidemic follicular disease.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of discharge is most typical of allergic conjunctivitis?",o:["Purulent","Watery","Ropy mucoid","Bloody","Serosanguinous"],a:2,e:"Allergic conjunctivitis commonly produces stringy or ropy mucoid discharge along with itching and bilateral redness.<br><br>Purulent discharge (A) suggests bacterial infection, while watery discharge (B) is more typical of viral conjunctivitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which complication may occur in severe gonococcal conjunctivitis?",o:["Corneal perforation","Retinal detachment","Optic atrophy","Cataract","Vitreous hemorrhage"],a:0,e:"Neisseria gonorrhoeae can rapidly invade intact corneal epithelium, leading to ulceration and perforation.<br><br>This aggressive corneal involvement makes hyperacute gonococcal conjunctivitis an ophthalmic emergency.<br><br>Retinal detachment (B) and vitreous hemorrhage (E) are unrelated posterior segment conditions.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which sign is most characteristic of trachoma?",o:["Arlt line","Papilledema","Kayser-Fleischer ring","Hyphema","Roth spots"],a:0,e:"Arlt line refers to linear conjunctival scarring seen in trachoma and is a classic high-yield ophthalmology sign.<br><br>Trachoma also produces Herbert pits, trichiasis, and corneal pannus.<br><br>Kayser-Fleischer ring (C) occurs in Wilson disease, while hyphema (D) represents blood in the anterior chamber.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition is strongly associated with shield ulcer formation?",o:["Viral conjunctivitis","Vernal keratoconjunctivitis","Bacterial conjunctivitis","Episcleritis","Pinguecula"],a:1,e:"Vernal keratoconjunctivitis can produce shield ulcers due to chronic mechanical trauma and toxic inflammatory mediators affecting the corneal epithelium.<br><br>Simple bacterial conjunctivitis (C) rarely causes shield ulcers. Episcleritis (D) is a benign inflammatory scleral condition.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of conjunctivitis is most contagious?",o:["Viral conjunctivitis","Allergic conjunctivitis","Dry eye disease","Toxic conjunctivitis","Episcleritis"],a:0,e:"Adenoviral conjunctivitis is highly contagious and spreads rapidly through direct contact, contaminated instruments, and respiratory droplets.<br><br>Outbreaks commonly occur in schools and clinics.<br><br>Allergic conjunctivitis (B) is not infectious. Episcleritis (E) is inflammatory and noncontagious.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with conjunctivitis has giant cobblestone papillae and limbal Horner-Trantas dots. Which diagnosis is most likely?",o:["Bacterial conjunctivitis","Vernal keratoconjunctivitis","Trachoma","Epidemic keratoconjunctivitis","Chlamydial conjunctivitis"],a:1,e:"Horner-Trantas dots are collections of eosinophils at the limbus and are classically associated with vernal keratoconjunctivitis.<br><br>Cobblestone papillae are another hallmark feature.<br><br>Trachoma (C) causes follicles and conjunctival scarring rather than eosinophilic limbal dots.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which type of conjunctivitis commonly occurs with upper respiratory tract infection?",o:["Viral conjunctivitis","Allergic conjunctivitis","Vernal keratoconjunctivitis","Toxic conjunctivitis","Dry eye syndrome"],a:0,e:"Adenoviral conjunctivitis frequently accompanies upper respiratory tract infection and fever.<br><br>Patients usually develop watery discharge, follicles, and preauricular lymph node enlargement.<br><br>Allergic conjunctivitis (B) is associated with atopy rather than viral prodrome.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which discharge is most typical in viral conjunctivitis?",o:["Thick purulent","Bloody","Ropy mucous","Watery","Caseous"],a:3,e:"Watery discharge is characteristic of viral conjunctivitis, particularly adenoviral infection.<br><br>Associated findings include follicles and preauricular lymphadenopathy.<br><br>Ropy mucus (C) is more typical of allergic conjunctivitis, while purulent discharge (A) suggests bacterial infection.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which condition is associated with Herbert pits?",o:["Vernal keratoconjunctivitis","Episcleritis","Viral conjunctivitis","Trachoma","Keratoconus"],a:3,e:"Herbert pits are limbal depressions caused by healed follicles and are considered classic signs of trachoma.<br><br>They are frequently asked in postgraduate ophthalmology examinations.<br><br>Keratoconus (E) causes corneal ectasia rather than conjunctival scarring disease.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctivitis is most strongly associated with eosinophils?",o:["Viral conjunctivitis","Chlamydial conjunctivitis","Gonococcal conjunctivitis","Allergic conjunctivitis","Bacterial conjunctivitis"],a:3,e:"Eosinophils play a major role in allergic conjunctivitis and vernal keratoconjunctivitis.<br><br>Their inflammatory mediators contribute to itching, papillae formation, and corneal involvement.<br><br>Viral conjunctivitis (A) is lymphocyte predominant rather than eosinophilic.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding bacterial conjunctivitis is most accurate?",o:["Itching is the hallmark symptom","Preauricular lymphadenopathy is always present","Mucopurulent discharge is common","It is usually associated with giant papillae","It commonly causes Horner-Trantas dots"],a:2,e:"Bacterial conjunctivitis typically presents with mucopurulent discharge and eyelid crusting, especially in the morning.<br><br>Conjunctival hyperemia and papillary reaction are common accompanying findings.<br><br>Preauricular lymphadenopathy is more typical of viral conjunctivitis, while giant papillae and Horner-Trantas dots suggest allergic/vernal disease.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 19-year-old hostel student develops sudden onset redness, watering, photophobia, and foreign body sensation in one eye followed by involvement of the second eye after two days. Examination reveals follicles on the inferior palpebral conjunctiva and tender preauricular lymphadenopathy. Which diagnosis is most likely?",o:["Allergic conjunctivitis","Episcleritis","Bacterial conjunctivitis","Viral conjunctivitis","Acute angle-closure glaucoma"],a:3,e:"Adenoviral conjunctivitis classically begins in one eye and spreads to the fellow eye within days.<br><br>Watery discharge and recent respiratory illness are additional important clues. The condition is highly contagious and spreads rapidly in schools and hostels.<br><br>Bacterial conjunctivitis (C) usually produces mucopurulent discharge rather than watery tearing. Acute angle-closure glaucoma (E) causes severe pain and corneal edema rather than follicles.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 7-year-old boy presents every summer with severe itching, ropy discharge, photophobia, and repeated eye rubbing. Examination reveals giant cobblestone papillae on the upper tarsal conjunctiva and limbal Horner-Trantas dots. Which diagnosis is most likely?",o:["Vernal keratoconjunctivitis","Viral conjunctivitis","Gonococcal conjunctivitis","Trachoma","Episcleritis"],a:0,e:"Vernal keratoconjunctivitis commonly affects young atopic boys and worsens during warm seasons.<br><br>Intense itching is usually the dominant symptom, and severe disease may produce shield ulcers involving the cornea. Trachoma staging and its blinding sequelae is a classic high-yield public-health correlate.<br><br>Trachoma (D) causes follicles and conjunctival scarring rather than giant papillae and eosinophilic limbal dots.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctivitis is most strongly associated with preauricular lymphadenopathy?",o:["Allergic conjunctivitis","Viral conjunctivitis","Dry eye syndrome","Toxic conjunctivitis","Blepharitis"],a:1,e:"Follicular conjunctival reaction and watery discharge are additional important features.<br><br>Allergic conjunctivitis (A) primarily causes itching and papillae without significant lymphadenopathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A newborn develops severe purulent conjunctivitis 3 days after delivery. The eyelids are swollen and copious pus is continuously discharging. Which organism is most likely responsible?",o:["Adenovirus","Chlamydia trachomatis","Staphylococcus epidermidis","Neisseria gonorrhoeae","Moraxella"],a:3,e:"Gonococcal ophthalmia neonatorum classically presents within the first few days after birth with hyperacute purulent conjunctivitis. Public recall discussions repeatedly identify gonococcus as the cause of profuse neonatal purulent discharge.<br><br>Rapid corneal involvement and perforation may occur because Neisseria can penetrate intact corneal epithelium. Immediate systemic treatment is essential.<br><br>Chlamydial conjunctivitis (B) usually appears later, around 5-14 days after birth.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most characteristic of allergic conjunctivitis?",o:["Severe pain","Diplopia","Itching","Colored halos","Floaters"],a:2,e:"Associated findings include bilateral redness, tearing, and ropy discharge.<br><br>Severe pain (A) should raise suspicion for corneal or intraocular pathology rather than simple conjunctival allergy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 14-year-old boy from a rural endemic area presents with chronic redness, recurrent irritation, and progressive inward turning of eyelashes. Examination shows superior tarsal conjunctival scarring and Herbert pits near the limbus. Which diagnosis is most likely?",o:["Vernal keratoconjunctivitis","Viral conjunctivitis","Trachoma","Bacterial conjunctivitis","Episcleritis"],a:2,e:"Trachoma is caused by Chlamydia trachomatis and remains an important cause of preventable blindness in endemic regions.<br><br>Repeated infection leads to conjunctival fibrosis, entropion, trichiasis, and corneal scarring.<br><br>Vernal keratoconjunctivitis (A) causes giant papillae rather than cicatricial conjunctival disease.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which discharge is most typical of bacterial conjunctivitis?",o:["Watery","Ropy mucoid","Mucopurulent","Bloody","Serous"],a:2,e:"Bacterial conjunctivitis typically produces mucopurulent discharge with eyelid crusting and sticking, especially in the morning.<br><br>Common organisms include Staphylococcus aureus, Streptococcus pneumoniae, and Haemophilus influenzae.<br><br>Watery discharge (A) is more typical of viral conjunctivitis, while ropy mucus (B) suggests allergic disease.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A medical student develops highly contagious conjunctivitis during an ophthalmology ward rotation. Examination reveals follicles, watery discharge, punctate keratitis, and subepithelial corneal infiltrates. Which diagnosis is most likely?",o:["Gonococcal conjunctivitis","Vernal conjunctivitis","Angular conjunctivitis","Epidemic keratoconjunctivitis","Toxic conjunctivitis"],a:3,e:"Epidemic keratoconjunctivitis is a severe adenoviral infection characterized by follicles, watery discharge, keratitis, and subepithelial infiltrates. Hospital outbreaks are commonly discussed in recall sources.<br><br>The condition spreads rapidly through contaminated instruments and direct contact.<br><br>Angular conjunctivitis (C) usually involves Moraxella infection affecting the canthi rather than diffuse follicular keratoconjunctivitis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctivitis is most strongly associated with giant papillae?",o:["Vernal keratoconjunctivitis","Viral conjunctivitis","Gonococcal conjunctivitis","Chlamydial conjunctivitis","Dry eye syndrome"],a:0,e:"Giant papillae or \"cobblestone papillae\" on the upper tarsal conjunctiva are classic findings in vernal keratoconjunctivitis.<br><br>The disease is associated with atopy and commonly affects children and adolescents.<br><br>Viral conjunctivitis (B) more commonly demonstrates follicles rather than giant papillary hypertrophy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with hyperacute conjunctivitis develops rapidly progressive corneal ulceration despite topical therapy. Which organism has the greatest ability to penetrate intact corneal epithelium?",o:["Adenovirus","Staphylococcus aureus","Chlamydia trachomatis","Neisseria gonorrhoeae","Moraxella"],a:3,e:"Neisseria gonorrhoeae uniquely penetrates intact corneal epithelium, causing rapidly progressive ulceration and possible perforation.<br><br>Copious purulent discharge and severe chemosis are characteristic clinical findings. Immediate systemic antibiotics are mandatory.<br><br>Adenovirus (A) causes follicular watery conjunctivitis rather than fulminant purulent corneal destruction.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A triangular fibrovascular conjunctival growth extending onto the cornea from the nasal side is most likely:",o:["Pinguecula","Episcleritis","Bitot spot","Pterygium","Conjunctival nevus"],a:3,e:"Pterygium is a triangular fibrovascular degeneration of conjunctiva that progressively encroaches onto the cornea.<br><br>Ultraviolet exposure, dust, and dry climates are important risk factors. Visual disturbance may occur because of induced astigmatism or visual axis involvement.<br><br>Pinguecula (A) is confined to conjunctiva and does not cross onto the cornea.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival degeneration does NOT cross the limbus?",o:["Pterygium","Pseudopterygium","Pannus","Pinguecula","Limbal dermoid"],a:3,e:"Pinguecula is a yellowish elevated conjunctival degeneration typically located nasally near the limbus but does not invade the cornea.<br><br>It is associated with chronic sun exposure and aging.<br><br>Pterygium (A) crosses the limbus and extends onto the corneal surface. Pseudopterygium (B) also adheres to cornea secondarily.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which environmental factor is most strongly associated with pterygium formation?",o:["Excessive near work","High myopia","Diabetes mellitus","Ultraviolet exposure","Smoking only"],a:3,e:"Chronic ultraviolet light exposure is the major etiological factor in pterygium development, especially in people living in hot, dusty climates. Public recall notes repeatedly mention UV exposure as the key risk factor.<br><br>Outdoor workers are commonly affected. Wind and dryness also contribute to conjunctival degeneration.<br><br>High myopia (B) and diabetes mellitus (C) are not major causative factors.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival degeneration is classically yellowish and located near the nasal limbus?",o:["Pterygium","Limbal dermoid","Conjunctival papilloma","Pinguecula","Bitot spot"],a:3,e:"Pinguecula appears as a yellow-white elevated conjunctival lesion adjacent to the limbus, most commonly nasally.<br><br>It represents elastotic degeneration of collagen fibers.<br><br>Pterygium (A) differs because it grows onto the cornea. Bitot spots (E) are keratinized foamy patches associated with vitamin A deficiency.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which degeneration is most likely to induce corneal astigmatism?",o:["Pinguecula","Episcleritis","Conjunctival nevus","Pterygium","Bitot spot"],a:3,e:"Pterygium may flatten the cornea and induce with-the-rule astigmatism as it extends over the corneal surface.<br><br>Large lesions can impair vision significantly.<br><br>Pinguecula (A) usually remains localized to conjunctiva and rarely affects corneal curvature. Episcleritis (B) is inflammatory rather than degenerative.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A conjunctival degeneration attached to the cornea only at its apex but not throughout its body is called:",o:["True pterygium","Pinguecula","Pseudopterygium","Limbal dermoid","Conjunctival cyst"],a:2,e:"Pseudopterygium develops secondary to inflammation or trauma and adheres to the cornea only at its apex.<br><br>A probe can often pass beneath its body, unlike true pterygium.<br><br>True pterygium (A) is firmly adherent throughout and usually occurs nasally within the palpebral fissure.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which vitamin deficiency is classically associated with Bitot spots?",o:["Vitamin B12 deficiency","Vitamin C deficiency","Vitamin D deficiency","Vitamin A deficiency","Vitamin K deficiency"],a:3,e:"Bitot spots are triangular foamy keratinized conjunctival lesions caused by vitamin A deficiency. Public recalls frequently associate Bitot spots with xerophthalmia.<br><br>Children in malnourished populations are particularly vulnerable.<br><br>Vitamin C deficiency (B) causes scurvy rather than xerophthalmic conjunctival lesions.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which location is most commonly affected by pterygium?",o:["Inferotemporal conjunctiva","Nasal interpalpebral area","Superior fornix","Palpebral conjunctiva","Caruncle only"],a:1,e:"Pterygium most commonly develops nasally within the interpalpebral fissure because this area receives maximum ultraviolet exposure.<br><br>Temporal lesions are less common.<br><br>Palpebral conjunctiva (D) is not the typical site for degenerative fibrovascular growth.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival degeneration commonly occurs in elderly individuals and outdoor workers?",o:["Pinguecula","Retinoblastoma","Chalazion","Optic neuritis","Papilledema"],a:0,e:"Pinguecula is a degenerative conjunctival lesion associated with aging, chronic sunlight exposure, and environmental irritation.<br><br>Outdoor workers in dusty climates are commonly affected.<br><br>Retinoblastoma (B) and optic neuritis (D) are unrelated ocular diseases involving retina and optic nerve respectively.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding pterygium is most accurate?",o:["It never affects vision","It commonly arises from palpebral conjunctiva","It may recur after surgical excision","It is always bilateral","It is unrelated to UV exposure"],a:2,e:"Pterygium recurrence after excision is an important clinical problem and is frequently emphasized in ophthalmology recalls.<br><br>Adjunctive therapies such as conjunctival autografting reduce recurrence risk.<br><br>The lesion commonly originates nasally and is strongly associated with ultraviolet exposure. Vision may be affected by induced astigmatism.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A fibrovascular conjunctival growth crossing the limbus and progressing toward the pupillary area is best described as:",o:["Pinguecula","Bitot spot","Conjunctival cyst","Pterygium","Episcleritis"],a:3,e:"Pterygium is a fibrovascular degenerative lesion extending from conjunctiva onto the cornea.<br><br>Progressive lesions may encroach on the visual axis and reduce vision.<br><br>Pinguecula (A) remains confined to conjunctiva without corneal invasion. Episcleritis (E) is inflammatory rather than degenerative.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which histopathological change is characteristic of pinguecula?",o:["Malignant melanocytes","Purulent infiltration","Granulomatous inflammation","Elastotic degeneration","Corneal edema"],a:3,e:"Pinguecula demonstrates elastotic degeneration of subepithelial collagen fibers caused by chronic environmental exposure.<br><br>The lesion appears yellow because of altered connective tissue.<br><br>Granulomatous inflammation (C) is not the primary pathology in pinguecula.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctival degeneration may produce restrictive ocular motility in advanced disease?",o:["Pinguecula","Conjunctival nevus","Bitot spot","Pterygium","Episcleritis"],a:3,e:"Large recurrent pterygia may scar and restrict ocular movements, especially abduction.<br><br>This is more likely in aggressive recurrent disease.<br><br>Pinguecula (A) is superficial and localized without significant motility restriction.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which lesion is commonly bilateral and associated with chronic actinic damage?",o:["Pinguecula","Retinal tear","Choroidal melanoma","Papilledema","Optic disc drusen"],a:0,e:"Pinguecula commonly occurs bilaterally in older individuals exposed to chronic ultraviolet radiation and environmental irritation.<br><br>It is considered a benign degenerative condition.<br><br>Retinal tear (B) and choroidal melanoma (C) are unrelated posterior segment pathologies.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctival degeneration is most likely to recur after surgery?",o:["Pinguecula","Conjunctival nevus","Bitot spot","Pterygium","Episcleritis"],a:3,e:"Pterygium recurrence is a major postoperative concern, especially in younger patients and aggressive lesions.<br><br>Conjunctival autografting significantly reduces recurrence rates.<br><br>Pinguecula (A) rarely requires surgery and has low recurrence significance.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with vitamin A deficiency most commonly develops which conjunctival lesion first?",o:["Pinguecula","Bitot spot","Pterygium","Episcleritis","Subconjunctival hemorrhage"],a:1,e:"Bitot spots are early xerophthalmic conjunctival lesions associated with vitamin A deficiency.<br><br>They appear as foamy keratinized patches near the limbus.<br><br>Pterygium (C) results from actinic degeneration rather than nutritional deficiency.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which test can help differentiate pseudopterygium from true pterygium?",o:["Schirmer test","Fluorescein angiography","Seidel test","Ishihara test","Probe test"],a:4,e:"A probe can be passed beneath the body of pseudopterygium because it is attached only at the apex.<br><br>True pterygium is adherent throughout and does not permit probe passage.<br><br>Schirmer test (A) measures tear secretion, while Ishihara testing (D) assesses color vision.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which degeneration is strongly linked with chronic dust and wind exposure?",o:["Pinguecula and pterygium","Retinal detachment","Papilledema","Macular hole","Vitreous hemorrhage"],a:0,e:"Both pinguecula and pterygium are associated with chronic ultraviolet light, dust, dryness, and windy environmental conditions.<br><br>Outdoor laborers are commonly affected.<br><br>Posterior segment disorders such as retinal detachment (B) are unrelated to conjunctival actinic degeneration.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival degeneration may appear wing-shaped?",o:["Pinguecula","Pterygium","Conjunctival nevus","Bitot spot","Episcleritis"],a:1,e:"Pterygium is often described as a wing-shaped fibrovascular growth extending from conjunctiva onto the cornea.<br><br>Its triangular morphology is a classic descriptive feature in ophthalmology recalls.<br><br>Pinguecula (A) remains localized without wing-like corneal extension.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which statement regarding pinguecula is most accurate?",o:["It commonly crosses onto the cornea","It is a malignant lesion","It represents conjunctival degeneration","It usually causes corneal perforation","It always requires surgery"],a:2,e:"Pinguecula is a benign degenerative lesion of conjunctiva associated with elastotic degeneration from chronic environmental exposure.<br><br>Most cases are asymptomatic and require only reassurance or lubrication.<br><br>Unlike pterygium, it does not invade the cornea. It is nonmalignant and rarely requires surgical intervention.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 52-year-old farmer from southern Punjab complains of gradual redness and irritation in his right eye for several years. Examination reveals a triangular fibrovascular growth arising nasally and extending 3 mm onto the cornea. Keratometry shows increasing with-the-rule astigmatism. Which diagnosis is most likely?",o:["Pinguecula","Pterygium","Episcleritis","Limbal dermoid","Conjunctival papilloma"],a:1,e:"Pterygium is a fibrovascular conjunctival degeneration extending across the limbus onto the cornea.<br><br>Ultraviolet exposure, dust, and chronic dryness are major etiological factors. Vision decreases when the lesion induces significant astigmatism or approaches the visual axis.<br><br>Pinguecula (A) remains confined to conjunctiva and does not produce progressive corneal extension.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 60-year-old outdoor laborer presents with bilateral yellow-white elevated lesions adjacent to the nasal limbus. The lesions are slightly raised but do not extend onto the cornea. Which diagnosis is most likely?",o:["Pseudopterygium","Pinguecula","Pterygium","Bitot spot","Conjunctival nevus"],a:1,e:"Pinguecula is a common conjunctival degeneration associated with chronic sunlight, dust, and wind exposure. It appears as yellowish elevated lesions near the limbus without corneal invasion.<br><br>The condition is frequently bilateral and more common in elderly outdoor workers.<br><br>Pterygium (C) differs because it crosses the limbus onto the cornea. Bitot spots (D) occur in vitamin A deficiency and appear foamy rather than elastotic.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 14-year-old malnourished child presents with night blindness and dry eyes. Examination reveals foamy triangular patches on the temporal bulbar conjunctiva. Which lesion is most likely present?",o:["Pinguecula","Pterygium","Episcleritis","Conjunctival papilloma","Bitot spots"],a:4,e:"Bitot spots are keratinized foamy conjunctival plaques associated with vitamin A deficiency and xerophthalmia. Public recalls commonly associate night blindness with these conjunctival lesions.<br><br>Children with malnutrition are particularly susceptible. Early treatment is important to prevent corneal xerosis and keratomalacia.<br><br>Pinguecula (A) is related to actinic degeneration rather than nutritional deficiency.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 46-year-old man presents with a conjunctival growth following previous alkali injury. The lesion adheres to the peripheral cornea but a probe can be passed beneath most of its body. Which diagnosis is most likely?",o:["True pterygium","Pinguecula","Pseudopterygium","Limbal dermoid","Conjunctival cyst"],a:2,e:"Pseudopterygium develops secondary to trauma or inflammation and adheres to the cornea only at its apex.<br><br>The probe test helps differentiate the two: a probe can be passed beneath a pseudopterygium but not under a true pterygium, which is adherent throughout.<br><br>True pterygium (A) is firmly adherent throughout and usually occurs nasally within the interpalpebral fissure.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 58-year-old fisherman complains of gradually worsening blurred vision and chronic redness. Examination reveals a fleshy vascularized nasal conjunctival lesion crossing the limbus and approaching the pupillary margin. Which mechanism most likely explains the visual deterioration?",o:["Optic nerve compression","Corneal astigmatism","Vitreous hemorrhage","Macular edema","Lens subluxation"],a:1,e:"Progressive pterygium commonly induces with-the-rule astigmatism by flattening and distorting the corneal surface.<br><br>Large lesions approaching the visual axis may directly obstruct vision as well.<br><br>Macular edema (D) and vitreous hemorrhage (C) are posterior segment causes of visual loss unrelated to conjunctival degeneration.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 67-year-old man develops recurrence of a fibrovascular conjunctival growth six months after excision. Which conjunctival degeneration most commonly demonstrates postoperative recurrence?",o:["Pinguecula","Bitot spot","Pterygium","Episcleritis","Conjunctival nevus"],a:2,e:"Recurrence risk is reduced by conjunctival autografting and careful surgical technique.<br><br>Pinguecula (A) rarely requires excision and has much lower recurrence significance.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 48-year-old welder presents with chronic irritation and a yellow elevated lesion near the nasal limbus. The lesion does not involve the cornea, and vision is normal. Which diagnosis is most likely?",o:["Pterygium","Pinguecula","Bitot spot","Pseudopterygium","Limbal dermoid"],a:1,e:"Pinguecula is an elastotic conjunctival degeneration commonly associated with chronic ultraviolet exposure, wind, and dust.<br><br>It remains localized to conjunctiva and usually causes mild irritation only.<br><br>Pterygium (A) extends onto the cornea and may affect vision through induced astigmatism.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A 40-year-old patient with recurrent pterygium develops restricted abduction due to dense fibrovascular scarring. Which complication is most likely responsible?",o:["Optic neuritis","Restrictive ocular motility","Retinal detachment","Vitreous prolapse","Orbital cellulitis"],a:1,e:"Advanced or recurrent pterygium may produce subconjunctival fibrosis leading to restriction of ocular movements, particularly abduction.<br><br>This is more common after repeated surgeries or aggressive fibrovascular proliferation.<br><br>Optic neuritis (A) and retinal detachment (C) are unrelated posterior segment disorders.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 62-year-old man from a desert region develops bilateral conjunctival degenerative lesions because of prolonged ultraviolet exposure and dry climate. Which lesion is most likely to remain confined to conjunctiva without crossing the limbus?",o:["Pterygium","Pinguecula","Pseudopterygium","Corneal pannus","Limbal dermoid"],a:1,e:"Pinguecula is a localized elastotic conjunctival degeneration and does not invade the cornea.<br><br>It commonly occurs in people exposed to chronic sunlight, wind, and dust.<br><br>Pterygium (A) is differentiated by progressive fibrovascular corneal extension beyond the limbus.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 17-year-old malnourished boy presents with conjunctival xerosis, foamy conjunctival plaques, and difficulty seeing at night. Which underlying deficiency is most likely responsible?",o:["Vitamin C deficiency","Vitamin B12 deficiency","Vitamin A deficiency","Vitamin D deficiency","Zinc deficiency"],a:2,e:"Vitamin A deficiency causes xerophthalmia characterized by conjunctival xerosis, Bitot spots, and night blindness.<br><br>Public recall MCQs frequently combine these three findings into a classic clinical scenario.<br><br>Severe untreated deficiency may progress to keratomalacia and irreversible blindness. Vitamin C deficiency (A) causes scurvy rather than xerophthalmia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A young adult presents with a well-circumscribed pigmented conjunctival lesion near the limbus that has remained stable for years. Which diagnosis is most likely?",o:["Conjunctival melanoma","Conjunctival nevus","Squamous cell carcinoma","Pterygium","Pinguecula"],a:1,e:"Conjunctival nevus is the most common benign melanocytic conjunctival tumor and usually appears during childhood or adolescence.<br><br>The lesion is typically well-circumscribed and stable for many years.<br><br>Conjunctival melanoma (A) usually develops later in life and demonstrates progressive enlargement and vascularity.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival tumor is most strongly associated with HIV infection?",o:["Conjunctival nevus","Pinguecula","Dermoid cyst","Squamous cell carcinoma","Papilloma"],a:3,e:"Conjunctival squamous cell carcinoma has increased incidence in immunocompromised patients, particularly those with HIV infection. Public recall posts frequently emphasize this association.<br><br>Ultraviolet exposure and HPV infection are additional risk factors.<br><br>Conjunctival nevus (A) is benign and unrelated to HIV-associated immunosuppression.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A gelatinous limbal conjunctival mass with prominent feeder vessels in an elderly patient is most suggestive of:",o:["Conjunctival papilloma","Squamous cell carcinoma","Pinguecula","Conjunctival cyst","Nevus"],a:1,e:"Conjunctival squamous cell carcinoma commonly appears as a gelatinous limbal lesion with feeder vessels and leukoplakia.<br><br>It usually arises in the interpalpebral area exposed to ultraviolet radiation.<br><br>Pinguecula (C) is degenerative and yellowish rather than vascularized malignant tissue.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival tumor most commonly contains intralesional cysts?",o:["Conjunctival melanoma","Squamous cell carcinoma","Dermoid","Lymphoma","Conjunctival nevus"],a:4,e:"Intralesional epithelial cysts are classic features of conjunctival nevus and help differentiate it from melanoma.<br><br>The lesion is usually mobile and well-demarcated.<br><br>Conjunctival melanoma (A) tends to be thicker, vascular, and progressive without characteristic cysts.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A salmon-pink subconjunctival lesion in an elderly patient is most suggestive of:",o:["Conjunctival lymphoma","Papilloma","Nevus","Squamous papilloma","Pinguecula"],a:0,e:"Conjunctival lymphoma classically presents as a painless salmon-pink patch beneath the conjunctiva. Public recalls frequently describe the \"salmon patch lesion.\"<br><br>The lesion is usually slow-growing and may be associated with systemic lymphoma.<br><br>Papilloma (B) is epithelial and wart-like rather than diffuse pink infiltration.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival lesion is strongly associated with HPV infection?",o:["Conjunctival papilloma","Conjunctival lymphoma","Melanoma","Pinguecula","Pterygium"],a:0,e:"Conjunctival papilloma is a benign epithelial tumor commonly associated with human papillomavirus infection.<br><br>It appears as a pedunculated or sessile vascular lesion.<br><br>Melanoma (C) is a malignant melanocytic tumor unrelated primarily to HPV infection.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which precursor lesion commonly gives rise to conjunctival melanoma?",o:["Pinguecula","Pterygium","Bitot spot","Primary acquired melanosis","Episcleritis"],a:3,e:"Primary acquired melanosis with atypia is an important precursor for conjunctival melanoma.<br><br>The risk of malignant transformation increases with atypical melanocytic proliferation.<br><br>Pinguecula (A) and pterygium (B) are degenerative lesions rather than melanocytic premalignant disorders.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A raised pigmented conjunctival lesion begins enlarging rapidly and develops feeder vessels. Which diagnosis should be suspected?",o:["Pinguecula","Conjunctival nevus","Conjunctival melanoma","Episcleritis","Papilloma"],a:2,e:"Rapid enlargement, increased pigmentation, and feeder vessel formation in a conjunctival melanocytic lesion strongly suggest malignant transformation into melanoma.<br><br>This is a classic high-yield warning sign in ophthalmology recalls.<br><br>Stable conjunctival nevus (B) usually demonstrates minimal change over time.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival tumor is most commonly located at the limbus?",o:["Squamous cell carcinoma","Dermoid cyst","Chalazion","Optic glioma","Papilledema"],a:0,e:"Conjunctival squamous neoplasia commonly arises at the limbus within the interpalpebral fissure exposed to ultraviolet light.<br><br>The lesion may appear gelatinous, leukoplakic, or papilliform.<br><br>Dermoid cyst (B) is congenital and usually superotemporal rather than limbal epithelial malignancy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctival tumor most commonly presents as a painless fleshy vascularized pedunculated lesion?",o:["Papilloma","Melanoma","Lymphoma","Nevus","Squamous carcinoma"],a:0,e:"Conjunctival papilloma is a benign epithelial tumor often appearing as a fleshy pedunculated vascular lesion.<br><br>HPV infection is strongly associated with its development.<br><br>Lymphoma (C) usually presents as a salmon-pink infiltrative patch rather than pedunculated growth.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with conjunctival melanoma is most likely to have which clinical feature?",o:["Intralesional cysts","Progressive enlargement","Foamy appearance","Cobblestone papillae","Horner-Trantas dots"],a:1,e:"Progressive growth, increased vascularity, and change in pigmentation are important suspicious features of conjunctival melanoma.<br><br>Such lesions require urgent ophthalmic evaluation and biopsy.<br><br>Intralesional cysts (A) are more typical of benign conjunctival nevus.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival tumor is usually benign and congenital?",o:["Conjunctival melanoma","Squamous carcinoma","Kaposi sarcoma","Lymphoma","Limbal dermoid"],a:4,e:"Limbal dermoid is a benign congenital choristoma commonly located inferotemporally at the limbus.<br><br>It contains ectodermal tissue such as hair follicles and sebaceous glands.<br><br>Squamous carcinoma (B) and melanoma (A) are acquired malignant lesions.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with AIDS develops a reddish vascular conjunctival lesion. Which tumor should be suspected?",o:["Nevus","Dermoid","Papilloma","Kaposi sarcoma","Pinguecula"],a:3,e:"Kaposi sarcoma is associated with HIV/AIDS and may involve the conjunctiva as a reddish vascular lesion.<br><br>The lesion often appears hemorrhagic or violaceous.<br><br>Pinguecula (E) is a degenerative yellow lesion unrelated to immunodeficiency.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctival tumor is malignant but often slow growing?",o:["Conjunctival lymphoma","Pinguecula","Papilloma","Nevus","Dermoid cyst"],a:0,e:"Conjunctival lymphoma is generally a low-grade malignant lymphoid proliferation with indolent progression.<br><br>Patients commonly present with painless salmon-pink subconjunctival lesions.<br><br>Papilloma (C) and nevus (D) are benign lesions.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which sign strongly favors conjunctival melanoma over nevus?",o:["Presence of cysts","Stable size","Feeder vessels","Childhood onset","Mobility"],a:2,e:"Prominent feeder vessels, rapid growth, and increasing pigmentation strongly suggest conjunctival melanoma.<br><br>Conjunctival nevus commonly contains cysts and often remains stable from childhood.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctival tumor commonly appears gelatinous and leukoplakic?",o:["Papilloma","Dermoid","Lymphoma","Nevus","Squamous cell carcinoma"],a:4,e:"Conjunctival squamous neoplasia often presents as a gelatinous limbal lesion with surface keratinization or leukoplakia.<br><br>Sun exposure is an important risk factor.<br><br>Lymphoma (C) usually appears as diffuse salmon-pink infiltration rather than leukoplakic epithelial growth.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival lesion is most likely benign in a child?",o:["Conjunctival melanoma","Squamous carcinoma","Kaposi sarcoma","Lymphoma","Conjunctival nevus"],a:4,e:"Conjunctival nevus is the most common melanocytic conjunctival lesion in children and young adults.<br><br>Most lesions remain benign and stable.<br><br>Melanoma (A) is rare in childhood and should be suspected if rapid change occurs.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A conjunctival lesion demonstrates diffuse flat pigmentation with atypia in a middle-aged adult. Which diagnosis is most likely?",o:["Primary acquired melanosis","Pinguecula","Pterygium","Papilloma","Dermoid"],a:0,e:"Primary acquired melanosis presents as unilateral acquired flat conjunctival pigmentation in middle-aged adults.<br><br>Lesions with atypia carry significant risk of melanoma development.<br><br>Pinguecula (B) is yellow-white elastotic degeneration rather than melanocytic pigmentation.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctival tumor most commonly requires systemic evaluation for associated hematologic malignancy?",o:["Papilloma","Nevus","Lymphoma","Pinguecula","Pterygium"],a:2,e:"Conjunctival lymphoma may represent localized disease or manifestation of systemic lymphoproliferative disorder.<br><br>Patients therefore require systemic hematologic evaluation.<br><br>Papilloma (A) and pinguecula (D) are localized benign conditions without systemic malignancy association.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which statement regarding conjunctival papilloma is most accurate?",o:["It is strongly associated with UV exposure only","It commonly presents as salmon-pink patch","It usually causes corneal perforation","It always becomes malignant","It is associated with HPV infection"],a:4,e:"Conjunctival papilloma is a benign epithelial lesion strongly associated with human papillomavirus infection.<br><br>It commonly appears as a pedunculated vascularized lesion.<br><br>Salmon-pink subconjunctival lesions suggest lymphoma, while malignant transformation of papilloma is uncommon.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 63-year-old farmer presents with a slowly enlarging gelatinous conjunctival lesion near the limbus of the right eye. Examination reveals leukoplakia and prominent feeder vessels. Which diagnosis is most likely?",o:["Conjunctival nevus","Squamous cell carcinoma","Pinguecula","Pterygium","Papilloma"],a:1,e:"Conjunctival squamous cell carcinoma classically presents as a gelatinous limbal mass with leukoplakia and feeder vessels.<br><br>The lesion commonly develops in elderly individuals with chronic ultraviolet exposure. HIV infection is also an important risk factor.<br><br>Pinguecula (C) is yellow and degenerative, while papilloma (E) is usually pedunculated and benign.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 28-year-old patient presents with a mobile pigmented conjunctival lesion containing small translucent cysts. The lesion has remained unchanged for many years. Which diagnosis is most likely?",o:["Conjunctival melanoma","Primary acquired melanosis","Conjunctival nevus","Squamous carcinoma","Lymphoma"],a:2,e:"Conjunctival nevus is the most common benign melanocytic conjunctival lesion and frequently contains intralesional cysts.<br><br>Long-term stability strongly supports a benign diagnosis.<br><br>Melanoma (A) is more likely to enlarge progressively and develop feeder vessels. Primary acquired melanosis (B) is usually flat rather than cystic and elevated.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"A painless salmon-pink subconjunctival patch in an elderly patient is most suggestive of:",o:["Kaposi sarcoma","Squamous papilloma","Conjunctival lymphoma","Pterygium","Dermoid"],a:2,e:"Conjunctival lymphoma classically presents as a painless salmon-pink subepithelial infiltrative lesion. Public ophthalmology recalls repeatedly describe the \"salmon patch appearance.\"<br><br>The disease is often indolent but may be associated with systemic lymphoproliferative disorders.<br><br>Kaposi sarcoma (A) is more vascular and reddish-purple rather than pale salmon-pink infiltration.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival lesion has the greatest malignant potential?",o:["Pinguecula","Conjunctival nevus","Primary acquired melanosis with atypia","Papilloma","Dermoid cyst"],a:2,e:"Primary acquired melanosis with atypia is a premalignant melanocytic lesion strongly associated with conjunctival melanoma development.<br><br>Risk increases with extensive atypical melanocytic involvement.<br><br>Conjunctival nevus (B) usually remains benign and stable throughout life.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient with HIV infection develops a vascular reddish conjunctival lesion. Which tumor should be suspected first?",o:["Conjunctival nevus","Kaposi sarcoma","Squamous papilloma","Pinguecula","Pterygium"],a:1,e:"Kaposi sarcoma is strongly associated with HIV/AIDS and may involve the conjunctiva as a vascular reddish-purple lesion.<br><br>This association is repeatedly highlighted in recall-based ophthalmology MCQs.<br><br>Pinguecula (D) is degenerative and yellowish rather than vascular and hemorrhagic.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A rapidly enlarging pigmented conjunctival lesion with feeder vessels and irregular margins is most likely:",o:["Conjunctival nevus","Pinguecula","Dermoid","Papilloma","Melanoma"],a:4,e:"Conjunctival melanoma should be suspected when a pigmented lesion demonstrates rapid enlargement, irregularity, and feeder vessel formation.<br><br>Conjunctival nevus (A) is usually stable and commonly contains cysts.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival tumor is most strongly associated with human papillomavirus infection?",o:["Papilloma","Melanoma","Lymphoma","Nevus","Pinguecula"],a:0,e:"Conjunctival papilloma is a benign epithelial tumor associated with HPV infection, especially types 6 and 11.<br><br>It commonly appears as a pedunculated fleshy vascular lesion.<br><br>Melanoma (B) is a malignant melanocytic tumor unrelated primarily to HPV infection.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A limbal conjunctival lesion demonstrates keratinization and leukoplakia in an elderly man with chronic UV exposure. Which diagnosis is most likely?",o:["Squamous cell carcinoma","Pinguecula","Dermoid cyst","Nevus","Episcleritis"],a:0,e:"Leukoplakia and keratinization in a limbal conjunctival lesion strongly suggest squamous neoplasia.<br><br>Ultraviolet exposure is one of the most important etiological factors.<br><br>Pinguecula (B) is degenerative without keratinized malignant epithelial changes.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which feature most strongly favors conjunctival nevus over melanoma?",o:["Feeder vessels","Rapid enlargement","Intralesional cysts","Irregular pigmentation","Progressive vascularity"],a:2,e:"Intralesional epithelial cysts are classic benign features favoring conjunctival nevus.<br><br>Stable size and childhood onset also support a benign diagnosis.<br><br>Rapid growth, vascularity, and feeder vessels suggest conjunctival melanoma instead.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with conjunctival lymphoma should undergo evaluation for which associated condition?",o:["Corneal ectasia","Cataract","Retinal detachment","Keratoconus","Systemic lymphoproliferative disease"],a:4,e:"Conjunctival lymphoma may represent localized ocular disease or manifestation of systemic lymphoma.<br><br>Systemic hematologic workup is therefore essential in all confirmed cases.<br><br>Corneal ectasia (A) and retinal detachment (C) are unrelated ocular disorders.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 22-year-old medical student develops bilateral red eyes during an ophthalmology ward rotation. Symptoms began in one eye with watering and foreign body sensation, then spread to the second eye after 48 hours. Examination shows follicles, tender preauricular lymphadenopathy, and fine punctate epithelial keratitis. Which diagnosis is most likely?",o:["Allergic conjunctivitis","Toxic conjunctivitis","Gonococcal conjunctivitis","Episcleritis","Viral conjunctivitis"],a:4,e:"Adenoviral conjunctivitis is highly contagious and commonly spreads rapidly in hospital settings.<br><br>Watery discharge and superficial punctate keratitis are common findings. Epidemic keratoconjunctivitis is the severe adenoviral variant frequently associated with subepithelial infiltrates.<br><br>Allergic conjunctivitis (A) primarily causes itching and papillae rather than follicles and lymphadenopathy.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which symptom is most characteristic of allergic conjunctivitis?",o:["Severe ocular pain","Floaters","Halos around lights","Diplopia","Itching"],a:4,e:"Itching is considered the hallmark symptom of allergic conjunctivitis and is one of the highest-yield distinctions in examination recalls.<br><br>Other findings include bilateral redness, tearing, papillae, and ropy mucoid discharge.<br><br>Severe pain (A) should prompt evaluation for corneal or intraocular pathology rather than simple allergy.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 12-year-old atopic boy presents every summer with severe itching, photophobia, thick ropy discharge, and constant eye rubbing. Slit-lamp examination reveals giant cobblestone papillae and limbal Horner-Trantas dots. Which diagnosis is most likely?",o:["Viral conjunctivitis","Vernal keratoconjunctivitis","Trachoma","Gonococcal conjunctivitis","Episcleritis"],a:1,e:"Vernal keratoconjunctivitis commonly affects young atopic males and worsens in warm climates. Public recall MCQs repeatedly describe giant papillae with Horner-Trantas dots as classic findings.<br><br>Shield ulcers may develop because of chronic inflammatory and mechanical corneal injury. Intense itching is usually the dominant symptom.<br><br>Trachoma (C) produces follicles and conjunctival scarring rather than giant papillary hypertrophy.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival degeneration commonly crosses the limbus onto the cornea?",o:["Pinguecula","Dermoid","Bitot spot","Episcleritis","Pterygium"],a:4,e:"Pterygium is a fibrovascular conjunctival degeneration extending onto the cornea, most commonly from the nasal side.<br><br>Chronic ultraviolet exposure and dusty environments are important risk factors.<br><br>Pinguecula (A) remains confined to conjunctiva and does not cross the limbus.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 60-year-old farmer from a desert area presents with progressive blurred vision and chronic ocular irritation. Examination reveals a triangular fibrovascular nasal conjunctival lesion extending centrally over the cornea and inducing marked with-the-rule astigmatism. Which diagnosis is most likely?",o:["Pinguecula","Pseudopterygium","Pterygium","Limbal dermoid","Squamous papilloma"],a:2,e:"Pterygium is strongly associated with ultraviolet exposure, dryness, and dusty climates. Public recall discussions frequently describe outdoor workers with nasal fibrovascular corneal extension.<br><br>Visual impairment commonly results from induced astigmatism or direct encroachment onto the visual axis. Recurrence after surgery is a major clinical issue.<br><br>Pinguecula (A) does not invade the cornea and rarely affects vision significantly.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival lesion is most strongly associated with vitamin A deficiency?",o:["Pterygium","Pinguecula","Bitot spot","Papilloma","Lymphoma"],a:2,e:"Bitot spots are keratinized foamy conjunctival lesions associated with xerophthalmia due to vitamin A deficiency.<br><br>Children with malnutrition are particularly susceptible.<br><br>Pterygium (A) and pinguecula (B) are degenerative lesions related to ultraviolet exposure rather than nutritional deficiency.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 68-year-old HIV-positive patient develops a gelatinous limbal conjunctival lesion with feeder vessels and leukoplakia. Which diagnosis is most likely?",o:["Conjunctival nevus","Squamous cell carcinoma","Pterygium","Pinguecula","Papilloma"],a:1,e:"Conjunctival squamous cell carcinoma commonly appears as a gelatinous limbal lesion with feeder vessels and keratinization.<br><br>Ultraviolet exposure and HPV infection also contribute significantly.<br><br>Pinguecula (D) is degenerative and yellow rather than vascularized malignant epithelium.<br><br><em>(Recall and Parson's Diseases of the Eye)</em>"},
  {q:"Which feature strongly favors conjunctival melanoma over conjunctival nevus?",o:["Intralesional cysts","Childhood onset","Stable size","Feeder vessels","Mobility"],a:3,e:"Prominent feeder vessels and progressive enlargement strongly suggest conjunctival melanoma rather than benign nevus.<br><br>Rapid change in pigmentation is another important warning sign.<br><br>Intralesional cysts (A) are classic benign features of conjunctival nevus.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A newborn develops profuse purulent conjunctivitis with marked lid edema three days after birth. Corneal ulceration develops rapidly despite topical treatment. Which organism is most likely responsible?",o:["Adenovirus","Chlamydia trachomatis","Staphylococcus epidermidis","Moraxella","Neisseria gonorrhoeae"],a:4,e:"Gonococcal ophthalmia neonatorum classically presents within the first few days of life with hyperacute purulent conjunctivitis. Public recall posts repeatedly identify gonococcus as the cause of severe neonatal purulent discharge.<br><br>Neisseria can penetrate intact corneal epithelium, causing rapid ulceration and perforation. Immediate systemic therapy is essential.<br><br>Chlamydial conjunctivitis (B) usually presents later, around 5-14 days after birth.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival tumor classically presents as a salmon-pink subconjunctival patch?",o:["Papilloma","Squamous carcinoma","Lymphoma","Nevus","Melanoma"],a:2,e:"Conjunctival lymphoma characteristically appears as a painless salmon-pink subepithelial lesion. Public recall MCQs frequently emphasize the \"salmon patch\" appearance.<br><br>Patients require systemic evaluation because ocular disease may be associated with systemic lymphoproliferative disorders.<br><br>Papilloma (A) is pedunculated and epithelial rather than diffuse subepithelial infiltration.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 30-year-old woman presents with unilateral acquired flat conjunctival pigmentation that has gradually enlarged over several years. Histology later demonstrates atypical melanocytes. Which lesion carries significant risk for melanoma development?",o:["Pinguecula","Primary acquired melanosis with atypia","Conjunctival nevus","Papilloma","Pterygium"],a:1,e:"Primary acquired melanosis with atypia is an important premalignant melanocytic lesion strongly associated with conjunctival melanoma development.<br><br>The degree of atypia determines malignant potential.<br><br>Conjunctival nevus (C) is usually benign and often stable for years.<br><br><em>(Recall and Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctivitis is most strongly associated with follicles?",o:["Allergic conjunctivitis","Dry eye disease","Vernal keratoconjunctivitis","Blepharitis","Viral conjunctivitis"],a:4,e:"Follicular conjunctival reaction is characteristic of viral and chlamydial conjunctivitis. Adenoviral infection is the classic cause in examination recalls.<br><br>Associated watery discharge and preauricular lymphadenopathy are common findings.<br><br>Allergic conjunctivitis (A) more commonly demonstrates papillary reaction rather than follicles.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 17-year-old malnourished adolescent presents with night blindness, conjunctival xerosis, and triangular foamy conjunctival plaques. Which diagnosis is most likely?",o:["Pinguecula","Allergic conjunctivitis","Pterygium","Episcleritis","Bitot spots due to vitamin A deficiency"],a:4,e:"Vitamin A deficiency causes xerophthalmia with conjunctival xerosis and Bitot spots. Public recall discussions frequently combine night blindness with foamy conjunctival plaques.<br><br>Severe deficiency may progress to corneal xerosis and keratomalacia causing irreversible blindness.<br><br>Pinguecula (A) is an actinic degeneration unrelated to nutritional deficiency.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival degeneration is most likely to recur after surgical excision?",o:["Pinguecula","Pterygium","Bitot spots","Episcleritis","Nevus"],a:1,e:"Conjunctival autografting and adjunctive therapies reduce recurrence rates.<br><br>Pinguecula (A) rarely requires surgery and has low recurrence significance.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 64-year-old patient presents with a vascularized pigmented conjunctival lesion that has enlarged rapidly over six months. Slit lamp examination shows feeder vessels and nodularity. Which diagnosis is most likely?",o:["Conjunctival nevus","Pinguecula","Lymphoma","Papilloma","Melanoma"],a:4,e:"Rapid enlargement, nodularity, and feeder vessels strongly suggest conjunctival melanoma.<br><br>Conjunctival melanoma may arise de novo or from primary acquired melanosis with atypia.<br><br>Conjunctival nevus (A) is usually stable and often contains intralesional cysts.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctivitis is most contagious?",o:["Allergic conjunctivitis","Episcleritis","Toxic conjunctivitis","Dry eye syndrome","Viral conjunctivitis"],a:4,e:"Adenoviral conjunctivitis spreads rapidly through contaminated hands, instruments, and respiratory droplets.<br><br>Hospital and school outbreaks are common.<br><br>Allergic conjunctivitis (A) is noninfectious despite marked redness and itching.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 55-year-old man develops a conjunctival lesion after severe chemical injury. The lesion attaches to the cornea only at one point, and a probe can pass underneath most of it. Which diagnosis is most likely?",o:["True pterygium","Pinguecula","Pseudopterygium","Dermoid cyst","Papilloma"],a:2,e:"Pseudopterygium develops secondary to trauma or inflammation and adheres to the cornea only at its apex.<br><br>The probe test is the classic differentiating feature from true pterygium.<br><br>True pterygium (A) is firmly adherent throughout and usually located nasally within the interpalpebral fissure.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"Which conjunctival tumor is most strongly associated with HPV infection?",o:["Melanoma","Pinguecula","Lymphoma","Nevus","Papilloma"],a:4,e:"Conjunctival papilloma is a benign epithelial tumor commonly associated with HPV infection.<br><br>It often appears as a pedunculated vascularized lesion.<br><br>Melanoma (A) is a malignant melanocytic tumor unrelated primarily to HPV infection.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A 45-year-old welder presents with bilateral yellow elevated conjunctival lesions adjacent to the limbus. They remain confined to conjunctiva and cause mild irritation only. Which diagnosis is most likely?",o:["Pterygium","Conjunctival lymphoma","Pseudopterygium","Limbal melanoma","Pinguecula"],a:4,e:"Pinguecula is an elastotic conjunctival degeneration associated with chronic ultraviolet exposure, wind, and dust.<br><br>The lesion remains localized to conjunctiva and does not cross the limbus.<br><br>Pterygium (A) extends onto the cornea and may induce astigmatism.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with conjunctival lymphoma should undergo evaluation for which associated systemic disease?",o:["Keratoconus","Retinal detachment","Lymphoproliferative disorder","Cataract","Corneal dystrophy"],a:2,e:"Conjunctival lymphoma may occur as localized ocular disease or as part of systemic lymphoproliferative malignancy.<br><br>Comprehensive systemic evaluation is therefore essential.<br><br>Keratoconus (A) and retinal detachment (B) are unrelated ocular disorders.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which discharge is most typical of bacterial conjunctivitis?",o:["Watery","Bloody","Ropy mucoid","Mucopurulent","Serous"],a:3,e:"Bacterial conjunctivitis classically presents with mucopurulent discharge and eyelid crusting.<br><br>Patients often complain that eyelids stick together in the morning.<br><br>Watery discharge (A) is more characteristic of viral conjunctivitis.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with severe vernal keratoconjunctivitis develops a superior corneal epithelial defect with plaque formation. Which complication is most likely?",o:["Shield ulcer","Corneal graft rejection","Retinal tear","Endophthalmitis","Hyphema"],a:0,e:"Shield ulcer is a classic corneal complication of severe vernal keratoconjunctivitis caused by chronic inflammatory and mechanical epithelial injury.<br><br>Public recalls frequently test this association.<br><br>Endophthalmitis (D) and retinal tear (C) are unrelated posterior segment pathologies.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival lesion is most likely benign in a child?",o:["Melanoma","Kaposi sarcoma","Squamous carcinoma","Lymphoma","Conjunctival nevus"],a:4,e:"Conjunctival nevus is the most common benign melanocytic lesion in children and adolescents.<br><br>Most remain stable throughout life.<br><br>Melanoma (A) is rare in children and should be suspected if rapid change occurs.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"A patient presents with chronic conjunctivitis, superior tarsal scarring, entropion, and trichiasis. Which disease is most likely responsible?",o:["Vernal keratoconjunctivitis","Trachoma","Viral conjunctivitis","Gonococcal conjunctivitis","Pinguecula"],a:1,e:"Trachoma caused by Chlamydia trachomatis produces chronic follicular conjunctivitis followed by conjunctival scarring.<br><br>Entropion and trichiasis eventually lead to corneal opacity and blindness.<br><br>Vernal keratoconjunctivitis (A) causes papillae and allergy-related inflammation rather than cicatricial disease.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival tumor most commonly presents with intralesional cysts?",o:["Melanoma","Squamous carcinoma","Lymphoma","Papilloma","Nevus"],a:4,e:"Intralesional epithelial cysts are characteristic benign features of conjunctival nevus and help differentiate it from melanoma.<br><br>The lesion is usually stable and well-circumscribed.<br><br>Melanoma (A) is more likely to enlarge progressively and develop feeder vessels.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient with gonococcal conjunctivitis develops rapid corneal ulceration. Which property of the organism explains this severe complication?",o:["It produces eosinophilic inflammation","It induces optic neuritis","It suppresses tear secretion","It causes retinal necrosis","It penetrates intact corneal epithelium"],a:4,e:"Neisseria gonorrhoeae uniquely penetrates intact corneal epithelium, producing rapidly progressive ulceration and possible perforation.<br><br>This is one of the most frequently tested emergency facts in conjunctivitis recalls.<br><br>The organism does not primarily cause optic neuritis or retinal necrosis.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival lesion is most associated with ultraviolet exposure and chronic environmental irritation?",o:["Pinguecula","Lymphoma","Papilloma","Nevus","Chalazion"],a:0,e:"Pinguecula represents elastotic degeneration caused by chronic ultraviolet exposure, dryness, dust, and wind.<br><br>Outdoor workers are frequently affected.<br><br>Papilloma (C) is HPV-related rather than actinic degeneration.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A patient develops bilateral seasonal conjunctivitis with intense itching and ropy discharge. Which inflammatory cell predominates in this condition?",o:["Neutrophils","Basophils only","Plasma cells","Macrophages","Eosinophils"],a:4,e:"Eosinophils are major inflammatory cells in allergic and vernal conjunctivitis and contribute to itching and corneal complications.<br><br>Their products contribute to epithelial damage and giant papillae formation.<br><br>Neutrophils (A) predominate in acute bacterial conjunctivitis instead.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
  {q:"Which conjunctival lesion is most likely to induce astigmatism?",o:["Pinguecula","Nevus","Bitot spot","Papilloma","Pterygium"],a:4,e:"Pterygium flattens the cornea and commonly induces with-the-rule astigmatism as it progresses centrally.<br><br>Large lesions may significantly impair visual acuity.<br><br>Pinguecula (A) remains confined to conjunctiva and usually does not alter corneal curvature.<br><br><em>(Parson's Diseases of the Eye)</em>"},
  {q:"A 70-year-old immunocompromised patient presents with a rapidly enlarging conjunctival mass containing keratinized white plaques and feeder vessels. Which diagnosis is most likely?",o:["Conjunctival lymphoma","Squamous cell carcinoma","Conjunctival nevus","Pinguecula","Papilloma"],a:1,e:"Conjunctival squamous cell carcinoma often appears as a vascularized gelatinous lesion with leukoplakia and feeder vessels.<br><br>Immunosuppression and ultraviolet exposure are important risk factors.<br><br>Lymphoma (A) classically appears as a salmon-pink infiltrative lesion rather than keratinized epithelial neoplasia.<br><br><em>(Kanski's Clinical Ophthalmology)</em>"},
];